import java.util.ArrayList;
import java.util.HashSet;
import java.util.Set;

class Solution {
    private void dfs(int r, int c, int r0, int c0, int[][] grid, ArrayList<int[]> island){
        if (r >= 0 && c >= 0 && r < grid.length && c < grid[0].length && grid[r][c] == 1) {
            grid[r][c] = 0;
            island.add(new int[]{r - r0, c - c0});
            dfs(r + 1, c, r0, c0, grid, island);
            dfs(r - 1, c, r0, c0, grid, island);
            dfs(r, c + 1, r0, c0, grid, island);
            dfs(r, c - 1, r0, c0, grid, island);
        }
    }

    private String normalize(ArrayList<int[]> island) {
        ArrayList<String> ret = new ArrayList<>();
        for (int[] p : island) {
            int x = p[0];
            int y = p[1];
            ret.add(x + "," + y);
            ret.add(x + "," + -y);
            ret.add(-x + "," + y);
            ret.add(-x + "," + -y);
            ret.add(y + "," + x);
            ret.add(y + "," + -x);
            ret.add(-y + "," + x);
            ret.add(-y + "," + -x);
        }
        ret.sort(String::compareTo);
        return String.join(" ", ret);
    }

    public int numDistinctIslands(int[][] grid) {
        Set<String> distinctIslands = new HashSet<>();
        for (int r = 0; r < grid.length; ++r) {
            for (int c = 0; c < grid[r].length; ++c) {
                if (grid[r][c] == 1) {
                    ArrayList<int[]> island = new ArrayList<>();
                    dfs(r, c, r, c, grid, island);
                    distinctIslands.add(normalize(island));
                }
            }
        }
        return distinctIslands.size();
    }
}
